// ============================================================
// APP.JS — TEMPLATE FLUMAP
// Motor principal — não edite diretamente
// Configure os dados em app-dados.js
// ============================================================

// Utilitários de formatação
const m6=['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
const meses=['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
const R=v=>'R$ '+Number(v).toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});
const P=v=>Number(v).toLocaleString('pt-BR',{minimumFractionDigits:1,maximumFractionDigits:1})+'%';
const setCurrencyMask=(inputId)=>{const el=document.getElementById(inputId);if(!el)return;el.addEventListener('input',e=>{let v=e.target.value.replace(/\D/g,'');const n=Number(v)/100||0;e.target.value=n.toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});});el.addEventListener('blur',e=>{let v=e.target.value.replace(/\D/g,'');const n=Number(v)/100||0;e.target.value=n.toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});});};
const fmtD=d=>d?`${d.slice(8,10)}/${d.slice(5,7)}/${d.slice(0,4)}`:'—';
const mk=(y,m)=>y+'-'+String(m).padStart(2,'0');
const diasUteis=dia=>{const h=new Date(),a=h.getFullYear(),e=h.getMonth()+1,v=new Date(a,e-1,dia);if(v<h)return -1;let u=0,d=new Date(h);while(+d<=+v){if(d.getDay()!==0&&d.getDay()!==6)u++;d.setDate(d.getDate()+1)}return u-1;};

// Helpers dinâmicos para dados
const nomeSocio=id=>{if(!id||id==='empresa')return'Empresa';const s=SOCIOS.find(x=>x.id===id);return s?s.nome:id;};
const badgeSocio=id=>{if(!id||id==='empresa')return`<span style="background:var(--gr200);color:var(--gr5);padding:2px 6px;border-radius:3px;font-size:8px;font-weight:700">Empresa</span>`;const idx=SOCIOS.findIndex(x=>x.id===id);const styles=['background:var(--b1);color:var(--b6)','background:var(--g1);color:var(--g7)','background:var(--wa1);color:var(--warn)','background:var(--w1);color:var(--red)'];const style=styles[idx]||styles[styles.length-1];return`<span style="${style};padding:2px 6px;border-radius:3px;font-size:8px;font-weight:700">${nomeSocio(id)}</span>`;};
const nomeAtivo=id=>{if(!id)return'Empresa';if(DB.projecao&&DB.projecao[id])return DB.projecao[id].nome;return id;};
const optionsSocios=(incluirEmpresa=true)=>{const emp=incluirEmpresa?'<option value="empresa">Empresa</option>':'';return emp+SOCIOS.map(s=>`<option value="${s.id}">${s.nome}</option>`).join('');};
const optionsAtivos=()=>'<option value="">Empresa</option>'+Object.keys(PROJECAO).map(k=>`<option value="${k}">${PROJECAO[k].nome}</option>`).join('');
const avatarClass=(idx)=>idx===0?'av-f':idx===1?'av-n':'av-f';
const barClass=(idx)=>idx===0?'pf-blue':'pf-green';

let DB={},mês={y:2026,m:4},filt='todos',_ch={},sortCol='data',sortDir='asc',invSortCol='data',invSortDir='desc',gerSortCol='data',gerSortDir='desc',mostrarLance=true,filtDestino='todos';

function init(){const versaoApp=VERSAO_APP;const versaoSalva=localStorage.getItem('flumap_version');if(versaoSalva!==versaoApp){localStorage.clear();sessionStorage.clear();localStorage.setItem('flumap_version_mudou','true');}localStorage.setItem('flumap_version',versaoApp);// Se DB já foi inicializado (carregado do localStorage), não sobrescreva
if(!DB||!DB.pagamentos||DB.pagamentos.length===0){DB={socios:SOCIOS,pagamentos:PAGAMENTOS,recorrentes:RECORRENTES,projecao:JSON.parse(JSON.stringify(PROJECAO)),investimentos:INVESTIMENTOS};}else{// Se já tem dados, apenas garanta que projecao está no formato correto
if(!DB.projecao)DB.projecao=JSON.parse(JSON.stringify(PROJECAO));}const projecaoSalva=localStorage.getItem('flumap_projecao');if(projecaoSalva){try{DB.projecao=JSON.parse(projecaoSalva);}catch(e){console.log('Erro ao carregar projecao salva');}}atualizarTotaisSocios();const h=new Date();document.getElementById('hdr-date').textContent=h.toLocaleDateString('pt-BR',{weekday:'short',day:'2-digit',month:'short'});mês={y:h.getFullYear(),m:h.getMonth()+1};const modal=document.getElementById('modal-rec');modal.addEventListener('click',e=>{if(e.target.id==='modal-rec')closeModal();});const modalInv=document.getElementById('modal-invest');if(modalInv)modalInv.addEventListener('click',e=>{if(e.target.id==='modal-invest')closeModalInv();});const modalRecEdit=document.getElementById('modal-rec-edit');if(modalRecEdit)modalRecEdit.addEventListener('click',e=>{if(e.target.id==='modal-rec-edit')closeModalRecEdit();});const modalRecPag=document.getElementById('modal-rec-pag');if(modalRecPag)modalRecPag.addEventListener('click',e=>{if(e.target.id==='modal-rec-pag')closeModalRecPag();});['inv-inv','ei-inv'].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML='<option value="">Selecione...</option>'+optionsSocios(false);});['inv-cam','ei-cam','r-cam'].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML=optionsAtivos();});['el-quem','lq'].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML='<option value="">Selecione...</option>'+optionsSocios(true);});['lcam','el-cam'].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML=optionsAtivos();});['r-cat','re-cat','el-cat','lc'].forEach(id=>{const el=document.getElementById(id);if(el&&id!=='el-cat'&&id!=='lc')el.innerHTML='<option value="">Selecione...</option>'+Object.entries(CATS).map(([k,c])=>`<option value="${k}">${c.nome}</option>`).join('');});render('painel');}

function nav(id){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.querySelectorAll('.nav-item').forEach(n=>n.classList.remove('active'));document.getElementById('page-'+id).classList.add('active');const navItem=document.querySelector(`[onclick="nav('${id}')"]`);if(navItem)navItem.classList.add('active');toggleMenu(true);render(id);}

function render(id){try{const pages={painel:renderPainel,investimentos:renderInv,'investimentos-lancar':renderInvest,despesas:renderDesp,evolutivo:renderEvolutivo,projecao:renderProj,recorrentes:renderRec,lancamentos:renderLanc,alertas:renderAlt,gerenciar:renderGer};if(!pages[id]){console.error('Página não encontrada:',id);return;}pages[id]();}catch(e){console.error('ERRO em render:',e);alert('❌ Erro: '+e.message);}}

function toggleMenu(close){const sb=document.getElementById('sidebar');if(close){sb.classList.remove('open');return;}sb.classList.toggle('open');}

function renderPainel(){try{const tp=DB.pagamentos.filter(p=>(!p.tipo||p.tipo==='despesa')).reduce((s,p)=>s+p.valor,0);const tr=DB.pagamentos.filter(p=>p.tipo==='receita').reduce((s,p)=>s+p.valor,0);const ts=DB.socios.reduce((s,x)=>s+x.totalPago,0);const al=getAlertas();document.getElementById('hdr-n').textContent=al.length;document.getElementById('hdr-alert').style.display=al.length?'flex':'none';const h=document.getElementById('page-painel');h.innerHTML=`<p class="page-title">Painel Geral</p><p class="page-sub">Visão consolidada</p>${al.slice(0,2).map(a=>`<div class="alert alert-${a.n==='r'?'r':'w'}"><span class="a-icon">${a.n==='r'?'🚨':'⚠'}</span><div><strong>${a.t}</strong><br><span style="font-size:11px">${a.d}</span></div></div>`).join('')}<div class="kpi-grid"><div class="kpi" style="padding:8px"><div class="kpi-lbl" style="font-size:11px">Total Investido</div><div class="kpi-val" style="font-size:18px">${R(ts)}</div></div><div class="kpi" style="padding:8px;border-left-color:var(--g5)"><div class="kpi-lbl" style="font-size:11px">Total Receita</div><div class="kpi-val" style="font-size:18px;color:var(--g6)">${R(tr)}</div></div><div class="kpi r"><div class="kpi-lbl">Total Gasto</div><div class="kpi-val" style="font-size:18px">${R(tp)}</div></div><div class="kpi g"><div class="kpi-lbl">Saldo Caixa</div><div class="kpi-val" style="font-size:18px">${R(ts+tr-tp)}</div></div></div><div class="grid-2" style="gap:6px"><div class="card" style="padding:8px;grid-column:1/-1"><div class="card-title" style="font-size:11px">📈 Gastos Mensais</div><div class="chart-wrap painel-chart"><canvas id="ch1"></canvas></div></div></div><div class="grid-2" style="gap:8px;grid-template-columns:repeat(2,1fr)"><div class="card" style="padding:6px"><div class="card-title" style="font-size:11px">🤝 Sócios</div><div id="socios-p"></div></div><div class="card" style="padding:6px"><div class="card-title" style="font-size:11px">📅 Próximos Vencimentos</div><div id="venc-p"></div></div></div>`;const ms=getMeses();const lbl=ms.map(m=>m6[m.m-1]+'/'+String(m.y).slice(2));const vals=ms.map(m=>totPag(pagMes(m.y,m.m).filter(p=>(!p.tipo||p.tipo==='despesa'))));ch('ch1','bar',lbl,[{label:'Gastos',data:vals,backgroundColor:'rgba(21,101,192,.7)',borderColor:'#0D3B7A',borderWidth:1.5}],{scales:{y:{ticks:{callback:v=>R(v)}}}});const catK=Object.keys(CATS);const catV=catK.map(k=>DB.pagamentos.filter(p=>p.cat===k&&(!p.tipo||p.tipo==='despesa')).reduce((s,p)=>s+p.valor,0));const cf=catK.filter((_,i)=>catV[i]>0);const cv=catV.filter(v=>v>0);ch('ch2','doughnut',cf.map(c=>CATS[c].nome),[{data:cv,backgroundColor:cf.map(c=>CATS[c].cor),borderWidth:2,borderColor:'#fff'}],{plugins:{legend:{display:false}},cutout:'62%'});document.getElementById('socios-p').innerHTML=DB.socios.map((s,idx)=>{const pct=s.totalPago/ts*100;return `<div class="partner-row"><div class="av ${avatarClass(idx)}">${s.iniciais}</div><div style="flex:1"><div style="font-weight:700;font-size:12px">${s.nome}</div><div style="font-size:11px;color:var(--gr5)">Aportou ${R(s.totalPago)}</div><div class="prog"><div class="prog-fill ${barClass(idx)}" style="width:${pct}%"></div></div></div></div>`}).join('');document.getElementById('venc-p').innerHTML=DB.recorrentes.filter(r=>r.ativo).sort((a,b)=>a.dia-b.dia).map(r=>{const du=diasUteis(r.dia);const u=du>=0&&du<=3;return `<div style="display:flex;gap:8px;padding:8px 0;border-bottom:1px solid var(--gr200)"><span>${{consorcio:'🏦',sistemas:'💻',manutencao:'🔧'}[r.cat]||'📌'}</span><div style="flex:1"><div style="font-weight:600;font-size:11px">${r.nome}</div><div style="font-size:10px;color:var(--gr5)">Dia ${r.dia}</div></div><div style="text-align:right"><div style="font-weight:700;color:var(--b6)">${R(r.valorEsp)}</div>${u?`<span class="badge bw">⚠ ${du}d</span>`:''}</div></div>`}).join('')||'<div class="empty"><div class="empty-ico">✅</div>Sem recorrentes</div>';}catch(e){console.error('ERRO em renderPainel:',e);document.getElementById('page-painel').innerHTML='<p style="color:red;padding:20px">Erro: '+e.message+'</p>';}}

function renderInv(){const socioButtons=DB.socios.map(s=>`<button class="btn btn-o" onclick="filtPag('${s.id}')" id="btn-${s.id}">${s.nome}</button>`).join('');const h=document.getElementById('page-investimentos');h.innerHTML=`<p class="page-title">Pagamentos</p><p class="page-sub">Categorização dinâmica de gastos</p><div class="card"><div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:14px"><div class="card-title" style="margin:0">📊 Gastos por Categoria</div><button class="btn ${mostrarLance?'btn-p':'btn-o'}" onclick="toggleLance()" style="font-size:10px">Lance: ${mostrarLance?'ON':'OFF'}</button></div><div class="chart-wrap" style="height:240px"><canvas id="ch-cat-pag"></canvas></div></div><div class="card"><div class="card-title" style="margin-bottom:10px">📋 Detalhes de Pagamentos</div><div style="margin-bottom:10px;display:flex;gap:6px;flex-wrap:wrap"><button class="btn btn-o" onclick="filtPag('todos')" id="btn-todos">Todos</button>${socioButtons}<button class="btn btn-o" onclick="filtPag('empresa')" id="btn-empresa">Empresa</button></div><div class="tbl-wrap"><table id="tbl-pag"></table></div></div>`;filtPag('todos');}

function sortInv(col){if(invSortCol===col){invSortDir=invSortDir==='asc'?'desc':'asc';}else{invSortCol=col;invSortDir='asc';}renderInvest();}function filtroDestino(inv){filtDestino=inv;document.querySelectorAll('[id^="btn-dest-"]').forEach(btn=>btn.classList.remove('btn-p'));document.querySelectorAll('[id^="btn-dest-"]').forEach(btn=>btn.classList.add('btn-o'));document.getElementById('btn-dest-'+inv).classList.remove('btn-o');document.getElementById('btn-dest-'+inv).classList.add('btn-p');atualizarGraficoDestino();renderTabelaInvest();}function atualizarGraficoDestino(){const dados=filtDestino==='todos'?DB.investimentos:DB.investimentos.filter(i=>i.investidor===filtDestino);const destinos={};dados.forEach(i=>{destinos[i.destinado_para]=(destinos[i.destinado_para]||0)+i.valor;});const labels=Object.keys(destinos);const values=Object.values(destinos);const cores=['#1565C0','#43A047','#D97706','#DC2626','#7E57C2','#26A69A','#FF7043','#FFA726','#EF5350','#BDBDBD'];ch('ch-dest','bar',labels,[{label:'Investimentos',data:values,backgroundColor:cores.slice(0,labels.length),borderColor:cores.slice(0,labels.length),borderWidth:1}],{indexAxis:'x',scales:{y:{ticks:{callback:v=>R(v)}}},plugins:{legend:{display:false}}});}function renderTabelaInvest(){let sorted=[...DB.investimentos];if(filtDestino!=='todos'){sorted=sorted.filter(i=>i.investidor===filtDestino);}if(invSortCol==='data')sorted.sort((a,b)=>invSortDir==='asc'?a.data.localeCompare(b.data):b.data.localeCompare(a.data));else if(invSortCol==='investidor')sorted.sort((a,b)=>invSortDir==='asc'?a.investidor.localeCompare(b.investidor):b.investidor.localeCompare(a.investidor));else if(invSortCol==='descricao')sorted.sort((a,b)=>invSortDir==='asc'?a.descricao.localeCompare(b.descricao):b.descricao.localeCompare(a.descricao));else if(invSortCol==='valor')sorted.sort((a,b)=>invSortDir==='asc'?a.valor-b.valor:b.valor-a.valor);const t=document.getElementById('tbl-inv');t.innerHTML=`<tr><th onclick="sortInv('data')" style="cursor:pointer">Data ${invSortCol==='data'?invSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortInv('investidor')" style="cursor:pointer">Investidor ${invSortCol==='investidor'?invSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortInv('descricao')" style="cursor:pointer">Descrição ${invSortCol==='descricao'?invSortDir==='asc'?'▲':'▼':''}</th><th>Destinado para</th><th onclick="sortInv('valor')" style="cursor:pointer" class="tr">Valor ${invSortCol==='valor'?invSortDir==='asc'?'▲':'▼':''}</th><th style="text-align:center">Ações</th></tr>`+sorted.map(i=>`<tr><td>${fmtD(i.data)}</td><td>${badgeSocio(i.investidor)}</td><td style="font-size:11px">${i.descricao}</td><td style="font-size:10px;color:var(--gr5)">${i.destinado_para}</td><td class="tr" style="font-weight:600;color:var(--g6)">${R(i.valor)}</td><td style="text-align:center;font-size:9px;display:flex;gap:4px;justify-content:center"><button class="btn btn-o" onclick="abrirModalEditarInv('${i.id}')" style="padding:4px 6px">✏️</button><button class="btn btn-d" onclick="deletarInvestimento('${i.id}')" style="padding:4px 6px">🗑️</button></td></tr>`).join('');}function renderInvest(){const totSocios=DB.investimentos.filter(i=>i.investidor!=='empresa').reduce((s,i)=>s+i.valor,0);const h=document.getElementById('page-investimentos-lancar');h.innerHTML=`<p class="page-title">Lançar Novo Investimento</p><p class="page-sub">Registre aportes e investimentos</p><button class="btn btn-s" onclick="abrirModalInv()" style="margin-bottom:14px">💰 Novo Investimento</button><div class="grid-2" style="gap:8px;grid-template-columns:1fr 1fr 2fr;margin-bottom:14px"><div class="card" style="padding:14px 16px;display:flex;flex-direction:column;justify-content:center;border-left:4px solid var(--g5)"><div style="font-size:10px;font-weight:700;color:var(--gr5);text-transform:uppercase;letter-spacing:.4px;margin-bottom:6px">💰 Total Investido</div><div style="font-size:22px;font-weight:800;color:var(--gr9);white-space:nowrap">${R(totSocios)}</div></div><div class="card" style="padding:10px 12px;display:flex;flex-direction:column;justify-content:center"><div class="card-title" style="font-size:10px;margin-bottom:6px">💼 Saldo por Sócio</div><div id="inv-s"></div></div><div class="card"><div class="card-title">📍 Investimentos por Destino</div><div style="margin-bottom:8px;display:flex;gap:4px;flex-wrap:wrap">${['todos',...DB.socios.map(s=>s.id)].map((id,idx)=>`<button class="btn ${idx===0?'btn-p':'btn-o'}" onclick="filtroDestino('${id}')" id="btn-dest-${id}" style="font-size:9px">${id==='todos'?'Todos':nomeSocio(id)}</button>`).join('')}</div><div class="chart-wrap" style="height:160px"><canvas id="ch-dest"></canvas></div></div></div><div class="card"><div class="card-title">💼 Histórico de Investimentos</div><div class="tbl-wrap"><table id="tbl-inv"></table></div></div>`;document.getElementById('inv-s').innerHTML=DB.socios.map((s,idx)=>{const pct=totSocios>0?s.totalPago/totSocios*100:0;return `<div style="padding:6px 0;border-bottom:1px solid var(--gr200)"><div style="font-weight:700;font-size:12px;margin-bottom:2px">${s.nome}</div><div style="font-size:10px;color:var(--gr5);margin-bottom:4px">${R(s.totalPago)}</div><div class="prog" style="height:5px"><div class="prog-fill ${barClass(idx)}" style="width:${pct}%"></div></div></div>`}).join('');atualizarGraficoDestino();let sorted=[...DB.investimentos];if(invSortCol==='data')sorted.sort((a,b)=>invSortDir==='asc'?a.data.localeCompare(b.data):b.data.localeCompare(a.data));else if(invSortCol==='investidor')sorted.sort((a,b)=>invSortDir==='asc'?a.investidor.localeCompare(b.investidor):b.investidor.localeCompare(a.investidor));else if(invSortCol==='descricao')sorted.sort((a,b)=>invSortDir==='asc'?a.descricao.localeCompare(b.descricao):b.descricao.localeCompare(a.descricao));else if(invSortCol==='valor')sorted.sort((a,b)=>invSortDir==='asc'?a.valor-b.valor:b.valor-a.valor);const t=document.getElementById('tbl-inv');t.innerHTML=`<tr><th onclick="sortInv('data')" style="cursor:pointer">Data ${invSortCol==='data'?invSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortInv('investidor')" style="cursor:pointer">Investidor ${invSortCol==='investidor'?invSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortInv('descricao')" style="cursor:pointer">Descrição ${invSortCol==='descricao'?invSortDir==='asc'?'▲':'▼':''}</th><th>Destinado para</th><th onclick="sortInv('valor')" style="cursor:pointer" class="tr">Valor ${invSortCol==='valor'?invSortDir==='asc'?'▲':'▼':''}</th><th style="text-align:center">Ações</th></tr>`+sorted.map(i=>`<tr><td>${fmtD(i.data)}</td><td>${badgeSocio(i.investidor)}</td><td style="font-size:11px">${i.descricao}</td><td style="font-size:10px;color:var(--gr5)">${i.destinado_para}</td><td class="tr" style="font-weight:600;color:var(--g6)">${R(i.valor)}</td><td style="text-align:center;font-size:9px;display:flex;gap:4px;justify-content:center"><button class="btn btn-o" onclick="abrirModalEditarInv('${i.id}')" style="padding:4px 6px">✏️</button><button class="btn btn-d" onclick="deletarInvestimento('${i.id}')" style="padding:4px 6px">🗑️</button></td></tr>`).join('');}

function sortPag(col){if(sortCol===col){sortDir=sortDir==='asc'?'desc':'asc';}else{sortCol=col;sortDir='asc';}filtPag(filt);}function filtPag(f){filt=f;let l=f==='todos'?DB.pagamentos:f==='empresa'?DB.pagamentos.filter(p=>!p.quem||p.quem==='empresa'):DB.pagamentos.filter(p=>p.quem===f);l=l.filter(p=>(!p.tipo||p.tipo==='despesa'));const tot=totPag(l);let sorted=[...l];if(sortCol==='data')sorted.sort((a,b)=>sortDir==='asc'?a.data.localeCompare(b.data):b.data.localeCompare(a.data));else if(sortCol==='desc')sorted.sort((a,b)=>sortDir==='asc'?a.desc.localeCompare(b.desc):b.desc.localeCompare(a.desc));else if(sortCol==='valor')sorted.sort((a,b)=>sortDir==='asc'?a.valor-b.valor:b.valor-a.valor);const t=document.getElementById('tbl-pag');t.innerHTML=`<tr><th onclick="sortPag('data')" style="cursor:pointer">Data ${sortCol==='data'?sortDir==='asc'?'▲':'▼':''}</th><th onclick="sortPag('desc')" style="cursor:pointer">Descrição ${sortCol==='desc'?sortDir==='asc'?'▲':'▼':''}</th><th>Cat.</th><th>Ori</th><th>Quem</th><th class="tr" onclick="sortPag('valor')" style="cursor:pointer">Valor ${sortCol==='valor'?sortDir==='asc'?'▲':'▼':''}</th></tr>`+sorted.map(p=>`<tr><td>${fmtD(p.data)}</td><td style="font-size:11px">${p.desc}</td><td style="color:${CATS[p.cat]?CATS[p.cat].cor:'#000'};font-size:10px;font-weight:600">${CATS[p.cat]?CATS[p.cat].nome:'—'}</td><td style="font-size:10px">${nomeAtivo(p.cam).split(' ').pop()}</td><td>${badgeSocio(p.quem)}</td><td class="tr" style="font-weight:600">${R(p.valor)}</td></tr>`).join('')+`<tr class="hi"><td colspan="5">TOTAL (${l.length})</td><td class="tr">${R(tot)}</td></tr>`;atualizarGraficoCategorias(l);}

function renderDesp(){const pgs=pagMes(mês.y,mês.m).filter(p=>(!p.tipo||p.tipo==='despesa'));const tot=totPag(pgs);const ms=getMeses();const h=document.getElementById('page-despesas');h.innerHTML=`<p class="page-title">Controle de Despesas</p><p class="page-sub">Visão mensal das despesas</p><div style="display:flex;align-items:center;gap:10px;margin-bottom:16px"><button onclick="chMes(-1)">← Ant</button><span style="font-weight:700;min-width:120px;text-align:center">${meses[mês.m-1]} ${mês.y}</span><button onclick="chMes(1)">Próx →</button><button class="btn btn-o" style="margin-left:8px" onclick="chMes(0)">Mês Atual</button></div><div class="kpi-grid"><div class="kpi r"><div class="kpi-lbl">Total ${m6[mês.m-1]}</div><div class="kpi-val" style="font-size:18px">${R(tot)}</div><div class="kpi-sub">${pgs.length} itens</div></div><div class="kpi" style="padding:8px"><div class="kpi-lbl" style="font-size:11px">Acumulado</div><div class="kpi-val" style="font-size:18px">${R(totPag(DB.pagamentos.filter(p=>p.data.slice(0,7)<=mk(mês.y,mês.m)&&(!p.tipo||p.tipo==='despesa'))))}</div></div></div><div class="card" style="padding:12px"><div class="card-title" style="font-size:13px">📋 Categorias do Mês</div><div class="tbl-wrap"><table id="tbl-desp"></table></div></div><div class="card"><div class="card-title">📆 Acumulado Anual</div><div class="chart-wrap"><canvas id="ch4"></canvas></div></div>`;const catK=Object.keys(CATS);const rows=catK.map(k=>{const it=pgs.filter(p=>p.cat===k);if(!it.length)return '';const t=totPag(it);return `<tr><td colspan="3" style="padding:4px 8px"><details><summary><span style="font-size:11px;font-weight:600">${CATS[k].nome}</span><span style="margin-left:auto;font-weight:700;color:var(--red)">${R(t)}</span><span class="badge bgr">${it.length}</span></summary><div class="det-body"><table style="width:100%"><tr><th>Data</th><th>Desc</th><th>Quem</th><th class="tr">Valor</th></tr>${it.map(p=>`<tr><td>${fmtD(p.data)}</td><td>${p.desc}</td><td>${badgeSocio(p.quem)}</td><td class="tr">${R(p.valor)}</td></tr>`).join('')}</table></div></details></td></tr>`}).filter(Boolean).join('');document.getElementById('tbl-desp').innerHTML=`<tr><th colspan="2">Categoria</th><th class="tr">Total</th></tr>`+(rows||`<tr><td colspan="3" class="tc" style="padding:20px;color:var(--gr5)">Sem lançamentos</td></tr>`)+(tot?`<tr class="hi"><td colspan="2">TOTAL MÊS</td><td class="tr">${R(tot)}</td></tr>`:'');const lbl=ms.map(m=>m6[m.m-1]+'/'+String(m.y).slice(2));const catGr=[{id:'consorcio',ids:['consorcio','lance']},{id:'legal',ids:['legal']},{id:'equipamentos',ids:['equipamentos']},{id:'infraestrutura',ids:['infraestrutura']},{id:'sistemas',ids:['sistemas']},{id:'combustivel',ids:['combustivel']},{id:'manutencao',ids:['manutencao']}];const ds=catGr.map(g=>({label:CATS[g.ids[0]].nome,data:ms.map(m=>DB.pagamentos.filter(p=>p.data.startsWith(mk(m.y,m.m))&&g.ids.includes(p.cat)&&(!p.tipo||p.tipo==='despesa')).reduce((s,p)=>s+p.valor,0)),backgroundColor:CATS[g.ids[0]].cor+'CC',borderColor:CATS[g.ids[0]].cor,borderWidth:1,stack:'s'}));ch('ch4','bar',lbl,ds,{scales:{x:{stacked:true},y:{stacked:true,ticks:{callback:v=>R(v)}}},plugins:{legend:{position:'bottom'}}});}

function chMes(d){if(d===0){const h=new Date();mês={y:h.getFullYear(),m:h.getMonth()+1};}else{let{y,m}=mês;m+=d;if(m>12){m=1;y++;}if(m<1){m=12;y--;}mês={y,m};}renderDesp();}

function renderProj(){const h=document.getElementById('page-projecao');h.innerHTML='<p class="page-title">Por Ativo</p><p class="page-sub">Resultado financeiro mensal — clique em Editar para ajustar</p>';const calcProj=(id)=>{const p=DB.projecao[id];const imp=p.faturamentoBruto*p.impostoPerc;const fL=p.faturamentoBruto-imp;const tC=p.custos.reduce((s,c)=>s+c.valor,0);const lc=fL-tC;const marg=fL>0?lc/fL*100:0;return {imp,fL,tC,lc,marg};};const ativos=Object.keys(DB.projecao);const calcs=ativos.map(id=>({id,calc:calcProj(id)}));const totFat=calcs.reduce((s,a)=>s+DB.projecao[a.id].faturamentoBruto,0);const totCustos=calcs.reduce((s,a)=>s+a.calc.tC,0);const avgMarg=calcs.length>0?calcs.reduce((s,a)=>s+a.calc.marg,0)/calcs.length:0;const consolidDiv=document.createElement('div');consolidDiv.className='card';consolidDiv.innerHTML=`<div class="card-title">📊 Visão Consolidada</div><div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px"><div><div style="font-size:11px;color:var(--gr5);font-weight:700">Receita Total</div><div style="font-size:20px;font-weight:800;color:var(--b6)">${R(totFat)}</div></div><div><div style="font-size:11px;color:var(--gr5);font-weight:700">Custos Totais</div><div style="font-size:20px;font-weight:800;color:var(--red)">${R(totCustos)}</div></div><div><div style="font-size:11px;color:var(--gr5);font-weight:700">Margem Média</div><div style="font-size:20px;font-weight:800;color:${avgMarg>=20?'var(--g6)':avgMarg>=10?'var(--warn)':'var(--red)'}">${P(avgMarg)}</div></div></div></div>`;h.appendChild(consolidDiv);ativos.forEach(id=>{const p=DB.projecao[id];const calc=calcProj(id);const margColor=calc.marg>=20?'var(--g6)':calc.marg>=10?'var(--warn)':'var(--red)';const pDiv=document.createElement('div');pDiv.className='card';pDiv.innerHTML=`<div style="display:flex;align-items:center;justify-content:space-between"><div class="card-title">🚛 ${p.nome} <span style="font-size:11px;color:var(--gr5)">${p.placa}</span></div><button onclick="editarProjCaminhao('${id}')" class="btn btn-o" style="font-size:10px">✏ Editar</button></div><table style="width:100%;font-size:11px"><tr><td style="color:var(--gr5)">Fat. Bruto</td><td class="tr" style="font-weight:700">${R(p.faturamentoBruto)}</td></tr><tr><td style="color:var(--gr5)">Impostos (${(p.impostoPerc*100).toFixed(1)}%)</td><td class="tr" style="color:var(--red)">(${R(calc.imp)})</td></tr><tr style="border-top:1px solid var(--gr200)"><td style="font-weight:600">Fat. Líquido</td><td class="tr" style="font-weight:700">${R(calc.fL)}</td></tr><tr><td colspan="2" style="padding:3px 0;font-size:9px;color:var(--gr5);font-weight:700">Custos</td></tr>${p.custos.map(c=>`<tr><td style="color:var(--gr5);padding-left:6px;font-size:10px">${c.nome}</td><td class="tr" style="color:var(--red);font-size:10px">(${R(c.valor)})</td></tr>`).join('')}<tr style="border-top:2px solid var(--gr200)"><td style="font-weight:600">Custos Total</td><td class="tr" style="font-weight:700;color:var(--red)">(${R(calc.tC)})</td></tr><tr style="background:var(--${calc.lc>=0?'b':'w'}1)"><td style="font-weight:700;font-size:12px">Lucro Mensal</td><td class="tr" style="font-weight:800;font-size:13px;color:var(--${calc.lc>=0?'b':'red'}-7)">${R(calc.lc)}</td></tr><tr><td style="color:var(--gr5)">Margem Líquida</td><td class="tr" style="font-weight:700;color:${margColor};font-size:12px">${P(calc.marg)}</td></tr></table>`;h.appendChild(pDiv);});const chartData=ativos.reduce((acc,id,idx)=>{const calc=calcProj(id);acc.fatBruto.push(DB.projecao[id].faturamentoBruto);acc.fL.push(calc.fL);acc.tC.push(calc.tC);acc.lucro.push(calc.lc);return acc;},{fatBruto:[],fL:[],tC:[],lucro:[]});const chartDiv=document.createElement('div');chartDiv.className='card';chartDiv.innerHTML='<div class="card-title">📊 Comparativo Financeiro</div><div class="chart-wrap"><canvas id="ch6"></canvas></div>';h.appendChild(chartDiv);const it=['Fat. Bruto','Fat. Líquido','Custos','Lucro'];const datasets=ativos.map((id,idx)=>{const cores=['rgba(21,101,192,.75)','rgba(67,160,71,.75)','rgba(217,119,6,.75)','rgba(220,38,38,.75)'];const corBorder=['#0D3B7A','#2E7D32','#D97706','#DC2626'];return{label:DB.projecao[id].nome,data:[chartData.fatBruto[idx],chartData.fL[idx],chartData.tC[idx],chartData.lucro[idx]],backgroundColor:cores[idx]||cores[0],borderColor:corBorder[idx]||corBorder[0],borderWidth:1.5};});ch('ch6','bar',it,datasets,{scales:{y:{ticks:{callback:v=>R(v)}}},plugins:{legend:{position:'bottom'}}});}

function renderRec(){const al=getAlertas().filter(a=>a.t.includes('Divergência'));const h=document.getElementById('page-recorrentes');h.innerHTML=`<p class="page-title">Despesas Recorrentes</p><p class="page-sub">Pagamentos fixos - Cadastro em Lançamentos</p>${al.map(a=>`<div class="alert alert-r"><span class="a-icon">🚨</span><div><strong>${a.t}</strong><br>${a.d}</div></div>`).join('')}<div id="rec-l"></div>`;const emojis={consorcio:'🏦',sistemas:'💻',manutencao:'🔧',jbs:'🚚',outros:'📦'};document.getElementById('rec-l').innerHTML=DB.recorrentes.map(r=>{const du=diasUteis(r.dia);const u=du>=0&&du<=3;const dv=r.hist.some(h=>h.status==='divergente');const ultimos4=r.hist.slice(-4);const borderColor=dv?'var(--red)':u?'var(--warn)':'var(--g5)';return `<div style="display:flex;align-items:flex-start;gap:14px;padding:12px 14px;margin-bottom:6px;background:#fff;border-radius:8px;border-left:4px solid ${borderColor};box-shadow:0 1px 2px rgba(0,0,0,.05)"><div style="flex:0 0 auto;text-align:center;padding-top:2px"><div style="font-size:28px;line-height:1;margin-bottom:2px">${emojis[r.cat]||'📌'}</div><span class="badge ${CATS[r.cat]?'bb':'bgr'}" style="font-size:7px;padding:2px 4px;display:block">${CATS[r.cat]?CATS[r.cat].nome.slice(0,7):'Outros'}</span></div><div style="flex:1;min-width:0"><div style="font-weight:700;font-size:14px;color:var(--gr9);margin-bottom:2px;line-height:1.2">${r.nome}</div><div style="font-size:10px;color:var(--gr5);margin-bottom:4px">📅 Dia ${r.dia} · ${r.cam?nomeAtivo(r.cam):'Empresa'} · ${u?'⚠ '+du+'d':dv?'🚨 Diverg.':'✓ OK'}</div><div style="display:flex;gap:4px;align-items:center;flex-wrap:wrap"><span style="font-size:8px;color:var(--gr5);font-weight:600;white-space:nowrap">Últ 4 meses</span><div style="display:flex;gap:2px">${ultimos4.map(h=>`<div style="width:12px;height:12px;border-radius:50%;background:${h.status==='ok'?'#4CAF50':h.status==='divergente'?'#FF6B6B':'#D0D0D0'};border:2px solid #fff;box-shadow:0 1px 2px rgba(0,0,0,.08);cursor:help" title="${h.mes}: ${h.status==='ok'?'OK':h.status==='divergente'?'Diverg.':'—'}"></div>`).join('')}</div></div></div><div style="flex:0 0 auto;text-align:right;padding-top:2px"><div style="font-weight:800;font-size:16px;color:var(--b6);line-height:1.1">${R(r.valorEsp)}</div><div style="font-size:9px;color:var(--gr5);margin-top:2px">/mês</div></div><div style="flex:0 0 auto;display:flex;flex-direction:column;gap:6px;padding-top:2px"><button class="btn btn-o" onclick="abrirModalRecEdit('${r.id}')" style="font-size:9px;padding:5px 10px;white-space:nowrap;min-width:72px">✏️ Editar</button><button class="btn btn-p" onclick="abrirModalRecPag('${r.id}')" style="font-size:9px;padding:5px 10px;white-space:nowrap;color:#fff!important;min-width:72px">➕ Pagto</button><button class="btn btn-d" onclick="deletarRecorrente('${r.id}')" style="font-size:9px;padding:5px 10px;white-space:nowrap;color:#fff!important;min-width:72px">🗑️ Excluir</button></div></div>`}).join('')||`<div class="empty"><div class="empty-ico">📋</div>Nenhuma recorrente cadastrada</div>`;}

function toggleRecorrentFields(){const isRec=document.getElementById('lrec').checked;const rf=document.getElementById('rec-fields');rf.style.display=isRec?'grid':'none';}
function renderLanc(){const h=document.getElementById('page-lancamentos');h.innerHTML=`<p class="page-title">Novo Lançamento</p><p class="page-sub">Registre pagamentos, receitas ou recorrentes</p><div class="card" style="max-width:600px"><form onsubmit="salvarLanc(event)"><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px"><div class="fg"><label>Tipo <span style="color:var(--red)">*</span></label><select id="lt" required><option value="despesa">Despesa</option><option value="receita">Receita</option></select></div><div class="fg"><label>Data <span style="color:var(--red)">*</span></label><input type="date" id="ld" required></div><div class="fg"><label>Nome <span style="color:var(--red)">*</span></label><input type="text" id="lds" placeholder="Descrição do lançamento"></div><div class="fg"><label>Valor <span style="color:var(--red)">*</span></label><input type="text" id="lv" inputmode="decimal" required></div><div class="fg"><label>Categoria <span style="color:var(--red)">*</span></label><select id="lc" required><option value="">Selecione...</option></select></div><div class="fg"><label>Quem <span style="color:var(--red)">*</span></label><select id="lq" required><option value="">Selecione...</option></select></div><div class="fg"><label>Origem</label><select id="lcam"><option value="">Empresa</option></select></div></div><div class="fg"><label style="display:flex;align-items:center;gap:8px;margin-top:10px"><input type="checkbox" id="lrec" onchange="toggleRecorrentFields()" style="width:18px;height:18px"><strong>Marcar como Recorrente</strong></label></div><div id="rec-fields" style="display:none;grid-template-columns:1fr 1fr;gap:10px"><div class="fg"><label>Dia (1-28)</label><input type="number" id="ldia" min="1" max="28"></div><div class="fg"><label>Tolerância (dias)</label><input type="number" id="ltol" value="2"></div></div><div class="btn-row"><button type="submit" class="btn btn-p">Salvar</button><button type="reset" class="btn btn-o">Limpar</button></div></form></div>`;document.getElementById('ld').value=new Date().toISOString().slice(0,10);document.getElementById('lc').innerHTML='<option value="">Selecione...</option>'+Object.entries(CATS).map(([id,c])=>`<option value="${id}">${c.nome}</option>`).join('');document.getElementById('lq').innerHTML='<option value="">Selecione...</option>'+optionsSocios(true);document.getElementById('lcam').innerHTML=optionsAtivos();setCurrencyMask('lv');}

function salvarLanc(e){e.preventDefault();const tipo=document.getElementById('lt').value;const valStr=document.getElementById('lv').value.replace(/\D/g,'');const p={id:'p'+Date.now(),desc:document.getElementById('lds').value||'Sem desc',valor:Number(valStr)/100||0,data:document.getElementById('ld').value,quem:document.getElementById('lq').value,cat:document.getElementById('lc').value,cam:document.getElementById('lcam').value,tipo:tipo};DB.pagamentos.push(p);const isRecorrente=document.getElementById('lrec').checked;if(isRecorrente){const dia=+document.getElementById('ldia').value;if(!dia||dia<1||dia>28){alert('Preencha dia válido para recorrente (1-28)');DB.pagamentos.pop();save();return;}const r={id:'r'+Date.now(),nome:p.desc,cat:p.cat,valorEsp:p.valor,dia:dia,cam:p.cam||'',tol:+document.getElementById('ltol').value||2,ativo:true,obs:'Criada a partir de lançamento manual',hist:[{mes:p.data.slice(0,7),pago:p.valor,data:p.data,status:'ok'}]};DB.recorrentes.push(r);}save();e.target.reset();document.getElementById('ld').value=new Date().toISOString().slice(0,10);document.getElementById('lrec').checked=false;document.getElementById('rec-fields').style.display='none';alert('✅ '+(isRecorrente?'Lançamento e recorrente criados!':'Salvo!'));}

function renderAlt(){const al=getAlertas();const h=document.getElementById('page-alertas');h.innerHTML=`<p class="page-title">Central de Alertas</p><p class="page-sub">Vencimentos e divergências</p>`+(al.length?al.map(a=>`<div class="alert alert-${a.n==='r'?'r':'w'}" style="display:flex;gap:12px;align-items:flex-start"><div style="display:flex;gap:8;align-items:center;flex:1"><span class="a-icon" style="font-size:18px">${a.n==='r'?'🚨':'⚠'}</span><div><strong style="font-size:11px">${a.t}</strong><br><span style="font-size:11px">${a.d}</span></div></div><button class="btn btn-d" onclick="deletarRecorrente('${a.id}')" style="font-size:9px;padding:6px 8px;flex-shrink:0">🗑️ Deletar</button></div>`).join(''):`<div class="empty"><div class="empty-ico">✅</div>Sem alertas</div>`)+`<div class="card" style="margin-top:14px"><div class="card-title">📅 Calendário Mensal</div>${DB.recorrentes.filter(r=>r.ativo).sort((a,b)=>a.dia-b.dia).map(r=>`<div style="display:flex;gap:8px;padding:10px 0;border-bottom:1px solid var(--gr200)"><div style="background:var(--b1);color:var(--b6);border-radius:6px;padding:4px 8px;font-weight:800;font-size:13px;min-width:36px;text-align:center">${r.dia}</div><div style="flex:1"><div style="font-weight:600;font-size:11px">${r.nome}</div><div style="font-size:9px;color:var(--gr5)">${nomeAtivo(r.cam)}</div></div><div style="text-align:right"><div style="font-weight:700;color:var(--b6)">${R(r.valorEsp)}</div></div></div>`).join('')}</div>`;}

function getAlertas(){const al=[];DB.recorrentes.filter(r=>r.ativo).forEach(r=>{const du=diasUteis(r.dia);if(du>=0&&du<=3)al.push({n:du<=1?'r':'w',t:`Vencimento: ${r.nome}`,d:`Dia ${r.dia} — ${R(r.valorEsp)} — ${du===0?'HOJE':du+' dia(s) útil(eis)'}`,id:r.id});r.hist.filter(h=>h.status==='divergente').forEach(h=>al.push({n:'r',t:`Divergência: ${r.nome}`,d:`${h.mes}: pago ${R(h.pago)} vs ${R(r.valorEsp)}`,id:r.id}));});return al;}

function deletarLancamento(id){if(confirm('Tem certeza que deseja deletar este lançamento?')){DB.pagamentos=DB.pagamentos.filter(p=>p.id!==id);save();renderGer();}}

function sortGer(col){if(gerSortCol===col){gerSortDir=gerSortDir==='asc'?'desc':'asc';}else{gerSortCol=col;gerSortDir='asc';}renderGer();}

function renderGer(){const h=document.getElementById('page-gerenciar');let despesas=DB.pagamentos.filter(p=>(!p.tipo||p.tipo==='despesa'));let receitas=DB.pagamentos.filter(p=>p.tipo==='receita');if(gerSortCol==='data'){despesas.sort((a,b)=>gerSortDir==='asc'?a.data.localeCompare(b.data):b.data.localeCompare(a.data));receitas.sort((a,b)=>gerSortDir==='asc'?a.data.localeCompare(b.data):b.data.localeCompare(a.data));}else if(gerSortCol==='nome'){despesas.sort((a,b)=>gerSortDir==='asc'?a.desc.localeCompare(b.desc):b.desc.localeCompare(a.desc));receitas.sort((a,b)=>gerSortDir==='asc'?a.desc.localeCompare(b.desc):b.desc.localeCompare(a.desc));}else if(gerSortCol==='valor'){despesas.sort((a,b)=>gerSortDir==='asc'?a.valor-b.valor:b.valor-a.valor);receitas.sort((a,b)=>gerSortDir==='asc'?a.valor-b.valor:b.valor-a.valor);}h.innerHTML=`<p class="page-title">Gerenciar Lançamentos</p><p class="page-sub">Editar ou deletar despesas e receitas</p><div class="card"><div class="card-title">📊 Despesas (${despesas.length})</div><div class="tbl-wrap"><table><tr><th onclick="sortGer('data')" style="cursor:pointer">Data ${gerSortCol==='data'?gerSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortGer('nome')" style="cursor:pointer">Nome ${gerSortCol==='nome'?gerSortDir==='asc'?'▲':'▼':''}</th><th>Categoria</th><th>Quem</th><th>Origem</th><th onclick="sortGer('valor')" style="cursor:pointer" class="tr">Valor ${gerSortCol==='valor'?gerSortDir==='asc'?'▲':'▼':''}</th><th>Ações</th></tr>${despesas.length?despesas.map(p=>`<tr><td>${fmtD(p.data)}</td><td style="font-size:11px">${p.desc}</td><td style="color:${CATS[p.cat]?CATS[p.cat].cor:'#000'};font-size:10px;font-weight:600">${CATS[p.cat]?CATS[p.cat].nome:'—'}</td><td>${badgeSocio(p.quem)}</td><td style="font-size:10px">${nomeAtivo(p.cam).split(' ').pop()}</td><td class="tr" style="font-weight:600;color:var(--red)">${R(p.valor)}</td><td style="font-size:9px;display:flex;gap:4px"><button class="btn btn-o" onclick="editarLancamento('${p.id}')" style="padding:4px 6px">✏️</button><button class="btn btn-d" onclick="deletarLancamento('${p.id}')" style="padding:4px 6px">🗑️</button></td></tr>`).join(''):`<tr><td colspan="7" class="tc" style="padding:20px;color:var(--gr5)">Nenhuma despesa registrada</td></tr>`}</table></div></div><div class="card"><div class="card-title">💰 Receitas (${receitas.length})</div><div class="tbl-wrap"><table><tr><th onclick="sortGer('data')" style="cursor:pointer">Data ${gerSortCol==='data'?gerSortDir==='asc'?'▲':'▼':''}</th><th onclick="sortGer('nome')" style="cursor:pointer">Nome ${gerSortCol==='nome'?gerSortDir==='asc'?'▲':'▼':''}</th><th>Quem</th><th onclick="sortGer('valor')" style="cursor:pointer" class="tr">Valor ${gerSortCol==='valor'?gerSortDir==='asc'?'▲':'▼':''}</th><th>Ações</th></tr>${receitas.length?receitas.map(p=>`<tr><td>${fmtD(p.data)}</td><td style="font-size:11px">${p.desc}</td><td>${badgeSocio(p.quem)}</td><td class="tr" style="font-weight:600;color:var(--g6)">${R(p.valor)}</td><td style="font-size:9px;display:flex;gap:4px"><button class="btn btn-o" onclick="editarLancamento('${p.id}')" style="padding:4px 6px">✏️</button><button class="btn btn-d" onclick="deletarLancamento('${p.id}')" style="padding:4px 6px">🗑️</button></td></tr>`).join(''):`<tr><td colspan="5" class="tc" style="padding:20px;color:var(--gr5)">Nenhuma receita registrada</td></tr>`}</table></div></div>`;};

function abrirModalEditarLanc(id){const p=DB.pagamentos.find(x=>x.id===id);if(!p)return;document.getElementById('el-id').value=id;document.getElementById('el-data').value=p.data;document.getElementById('el-nome').value=p.desc;document.getElementById('el-valor').value=R(p.valor).replace('R$ ','');document.getElementById('el-cat').value=p.cat;document.getElementById('el-quem').value=p.quem;document.getElementById('el-cam').value=p.cam||'';document.getElementById('modal-editar-lanc').classList.remove('hidden');setTimeout(()=>setCurrencyMask('el-valor'),100);}function closeModalEditarLanc(){document.getElementById('modal-editar-lanc').classList.add('hidden');}function salvarEdicaoLanc(){const id=document.getElementById('el-id').value;const p=DB.pagamentos.find(x=>x.id===id);if(!p)return;const valStr=document.getElementById('el-valor').value.replace(/\D/g,'');p.data=document.getElementById('el-data').value;p.desc=document.getElementById('el-nome').value;p.valor=Number(valStr)/100||0;p.cat=document.getElementById('el-cat').value;p.quem=document.getElementById('el-quem').value;p.cam=document.getElementById('el-cam').value;save();closeModalEditarLanc();renderGer();}function editarLancamento(id){document.getElementById('el-cat').innerHTML='<option value="">Selecione...</option>'+Object.entries(CATS).map(([k,c])=>`<option value="${k}">${c.nome}</option>`).join('');document.getElementById('el-quem').innerHTML='<option value="">Selecione...</option>'+optionsSocios(true);document.getElementById('el-cam').innerHTML=optionsAtivos();abrirModalEditarLanc(id);}

function renderEvolutivo(){const h=document.getElementById('page-evolutivo');const meses_calc=[];for(let m=1;m<=12;m++){meses_calc.push({y:2026,m});}const today=new Date();const mesAtual=today.getMonth()+1;const anoAtual=today.getFullYear();const evol=[];let saldoAnterior=0;meses_calc.forEach(mes=>{const investimentos=DB.investimentos?DB.investimentos.filter(i=>i.data.startsWith(mk(mes.y,mes.m))).reduce((s,i)=>s+i.valor,0):0;const receitas=DB.pagamentos.filter(p=>p.data.startsWith(mk(mes.y,mes.m))&&p.tipo==='receita').reduce((s,p)=>s+p.valor,0);const despesas=totPag(DB.pagamentos.filter(p=>p.data.startsWith(mk(mes.y,mes.m))&&((!p.tipo||p.tipo==='despesa'))));const saldo=saldoAnterior+investimentos+receitas-despesas;const ehFuturo=mes.y>anoAtual||(mes.y===anoAtual&&mes.m>mesAtual);evol.push({mes:meses[mes.m-1].slice(0,3),investimentos,receitas,despesas,saldo,ehFuturo});saldoAnterior=saldo;});const totInv=evol.reduce((s,e)=>s+e.investimentos,0);const totRec=evol.reduce((s,e)=>s+e.receitas,0);const totDesp=evol.reduce((s,e)=>s+e.despesas,0);const saldoFinal=evol[evol.length-1]?.saldo||0;h.innerHTML=`<p class="page-title">Visão Evolutiva</p><p class="page-sub">Fluxo de caixa mensal - 2026</p><div class="card"><div class="tbl-wrap"><table style="table-layout:fixed"><tr><th style="width:15%;text-align:center">Período</th><th style="width:21%;text-align:right">Investimentos</th><th style="width:21%;text-align:right">Receitas</th><th style="width:21%;text-align:right">Despesas</th><th style="width:22%;text-align:right">Saldo Caixa</th></tr>${evol.map((e,i)=>`<tr style="opacity:${e.ehFuturo?'0.5':'1'};transition:opacity 0.2s"><td style="font-weight:600;text-align:center;color:${e.ehFuturo?'var(--gr5)':'var(--gr9)'}">${e.mes}/26</td><td style="color:${e.ehFuturo?'rgba(217,119,6,0.5)':'var(--warn)'};font-weight:600;text-align:right">${R(e.investimentos)}</td><td style="color:${e.ehFuturo?'rgba(56,142,60,0.5)':'var(--g6)'};font-weight:600;text-align:right">${R(e.receitas)}</td><td style="color:${e.ehFuturo?'rgba(220,38,38,0.5)':'var(--red)'};font-weight:600;text-align:right">${R(e.despesas)}</td><td style="color:${e.ehFuturo?e.saldo>=0?'rgba(56,142,60,0.5)':'rgba(220,38,38,0.5)':e.saldo>=0?'var(--g6)':'var(--red)'};font-weight:700;text-align:right">${R(e.saldo)}</td></tr>`).join('')}<tr style="background:var(--gr200);border-top:2px solid var(--gr300)"><td style="font-weight:700;text-align:center">TOTAL</td><td style="color:var(--warn);font-weight:700;text-align:right">${R(totInv)}</td><td style="color:var(--g6);font-weight:700;text-align:right">${R(totRec)}</td><td style="color:var(--red);font-weight:700;text-align:right">${R(totDesp)}</td><td style="color:${saldoFinal>=0?'var(--g6)':'var(--red)'};font-weight:800;text-align:right">${R(saldoFinal)}</td></tr></table></div></div>`;};

function getMeses(){const k=new Set(DB.pagamentos.map(p=>p.data.slice(0,7)));return [...k].sort().map(k=>({y:+k.slice(0,4),m:+k.slice(5,7)}));}

function pagMes(y,m){return DB.pagamentos.filter(p=>p.data.startsWith(mk(y,m)));}

function totPag(arr){return arr.reduce((s,p)=>s+p.valor,0);}

function ch(id,type,labels,datasets,opts={}){const c=document.getElementById(id);if(!c)return;if(_ch[id])_ch[id].destroy();_ch[id]=new Chart(c,{type,data:{labels,datasets},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{labels:{font:{family:'Inter',size:10},boxWidth:10}},...(opts.plugins||{})},...opts}});}

function abrirModalRec(){document.getElementById('modal-rec').classList.remove('hidden');}

function closeModal(){document.getElementById('modal-rec').classList.add('hidden');}

function abrirModalInv(){document.getElementById('modal-invest').classList.remove('hidden');setTimeout(()=>setCurrencyMask('inv-val'),100);}

function closeModalInv(){document.getElementById('modal-invest').classList.add('hidden');}

function salvarRec(){const r={id:'r'+Date.now(),nome:document.getElementById('r-nome').value,cat:document.getElementById('r-cat').value,valorEsp:+document.getElementById('r-val').value,dia:+document.getElementById('r-dia').value,cam:document.getElementById('r-cam').value,tol:+document.getElementById('r-tol').value,ativo:true,obs:document.getElementById('r-obs').value,hist:[]};if(!r.nome||!r.valorEsp||!r.dia){alert('Preencha os campos');return;}DB.recorrentes.push(r);save();closeModal();renderRec();}

function alternarOutros(){const dest=document.getElementById('inv-dest').value;document.getElementById('inv-dest-outro').style.display=dest==='Outros'?'block':'none';}function salvarInvest(){const dest=document.getElementById('inv-dest').value;const destFinal=dest==='Outros'?document.getElementById('inv-dest-outro-txt').value||'Outros':dest;const valStr=document.getElementById('inv-val').value.replace(/\D/g,'');const inv={id:'inv'+Date.now(),descricao:document.getElementById('inv-desc').value,investidor:document.getElementById('inv-inv').value,data:document.getElementById('inv-data').value,valor:Number(valStr)/100||0,destinado_para:destFinal,status:'realizado',obs:document.getElementById('inv-obs').value};if(!inv.descricao||!inv.investidor||!inv.data||!inv.valor||!inv.destinado_para){alert('Preencha os campos obrigatórios');return;}if(inv.valor<=0){alert('Valor deve ser maior que zero');return;}if(dest==='Outros'&&!document.getElementById('inv-dest-outro-txt').value){alert('Descreva o destino');return;}DB.investimentos.push(inv);atualizarTotaisSocios();save();closeModalInv();renderInvest();atualizarGraficosInvestimento();renderPainel();}

function abrirModalRecEdit(id){const r=DB.recorrentes.find(x=>x.id===id);if(!r)return;document.getElementById('re-id').value=id;document.getElementById('re-nome').value=r.nome;document.getElementById('re-cat').value=r.cat;document.getElementById('re-val').value=r.valorEsp;document.getElementById('re-dia').value=r.dia;document.getElementById('re-tol').value=r.tol;document.getElementById('re-ativo').checked=r.ativo;document.getElementById('re-obs').value=r.obs;document.getElementById('modal-rec-edit').classList.remove('hidden');}

function closeModalRecEdit(){document.getElementById('modal-rec-edit').classList.add('hidden');}

function salvarRecEdit(){const id=document.getElementById('re-id').value;const r=DB.recorrentes.find(x=>x.id===id);if(!r)return;const dia=+document.getElementById('re-dia').value;if(dia<1||dia>28){alert('Dia deve ser entre 1 e 28');return;}r.valorEsp=+document.getElementById('re-val').value;r.dia=dia;r.tol=+document.getElementById('re-tol').value;r.ativo=document.getElementById('re-ativo').checked;r.obs=document.getElementById('re-obs').value;save();closeModalRecEdit();renderRec();}

function deletarRecorrente(id){if(confirm('Tem certeza que deseja deletar esta recorrente?')){DB.recorrentes=DB.recorrentes.filter(r=>r.id!==id);save();renderRec();}}function abrirModalRecPag(id){document.getElementById('rp-id').value=id;document.getElementById('rp-data').value=new Date().toISOString().slice(0,10);document.getElementById('rp-val').value='';document.getElementById('rp-status').value='ok';document.getElementById('modal-rec-pag').classList.remove('hidden');}

function closeModalRecPag(){document.getElementById('modal-rec-pag').classList.add('hidden');}

function salvarRecPag(){const id=document.getElementById('rp-id').value;const r=DB.recorrentes.find(x=>x.id===id);if(!r)return;const data=document.getElementById('rp-data').value;const valor=+document.getElementById('rp-val').value;const mes=data.slice(0,7);if(!data||!valor){alert('Preencha data e valor');return;}const pag={mes:mes,pago:valor,data:data,status:document.getElementById('rp-status').value};r.hist.push(pag);save();closeModalRecPag();renderRec();}

function criarRecorrenteDeDesp(id,desc,valor){const p=DB.pagamentos.find(x=>x.id===id);if(!p)return;const nome='Recorrente: '+desc;const cat=p.cat;const r={id:'r'+Date.now(),nome:nome,cat:cat,valorEsp:valor,dia:10,cam:p.cam||'',tol:2,ativo:true,obs:'Criada a partir de despesa '+p.desc,hist:[]};DB.recorrentes.push(r);save();render('recorrentes');}

function editarPlaca(cam_id){const p=DB.projecao[cam_id];const placa=prompt('Editar placa ('+cam_id+'):', p.placa);if(placa&&placa.trim()){p.placa=placa.trim();salvarProjecao();renderProj();}}function editarProjCaminhao(cam_id){const p=DB.projecao[cam_id];if(!p)return;document.getElementById('proj-cam').value=cam_id;document.getElementById('proj-fat').value=R(p.faturamentoBruto).replace('R$ ','');document.getElementById('proj-imp').value=(p.impostoPerc*100).toFixed(1);document.getElementById('proj-placa').value=p.placa;setTimeout(()=>setCurrencyMask('proj-fat'),100);document.getElementById('proj-custos').innerHTML=p.custos.map((c,i)=>`<div style="display:flex;gap:6px;margin-bottom:8px"><input type="text" value="${c.nome}" style="flex:1;padding:6px;border:1px solid var(--gr200);border-radius:4px" id="proj-c${i}-n" required><input type="text" value="${R(c.valor).replace('R$ ','')}" style="width:120px;padding:6px;border:1px solid var(--gr200);border-radius:4px" id="proj-c${i}-v" inputmode="decimal" required><button onclick="removerCusto(${i})" class="btn btn-d" style="padding:4px 8px;font-size:10px">✕ Remover</button></div>`).join('')+`<button onclick="adicionarCusto()" class="btn btn-o" style="margin-top:8px">➕ Novo Custo</button>`;p.custos.forEach((_,i)=>setTimeout(()=>setCurrencyMask(`proj-c${i}-v`),100));document.getElementById('modal-proj-edit').classList.remove('hidden');}

function adicionarCusto(){const custos=document.getElementById('proj-custos');const novoI=custos.querySelectorAll('div').length;const html=`<div style="display:flex;gap:6px;margin-bottom:8px"><input type="text" placeholder="Nome do custo" style="flex:1;padding:6px;border:1px solid var(--gr200);border-radius:4px" id="proj-c${novoI}-n"><input type="number" placeholder="0.00" step="0.01" style="width:120px;padding:6px;border:1px solid var(--gr200);border-radius:4px" id="proj-c${novoI}-v"><button onclick="removerCusto(${novoI})" class="btn btn-d" style="padding:4px 8px;font-size:10px">✕ Remover</button></div>`;custos.insertAdjacentHTML('beforeend',html);}

function removerCusto(i){document.getElementById('proj-c'+i+'-n').parentElement.remove();}

function salvarProjEdicao(){const camId=document.getElementById('proj-cam').value;const p=DB.projecao[camId];if(!p)return;const fatStr=document.getElementById('proj-fat').value.replace(/\D/g,'');const fat=Number(fatStr)/100||0;const imp=+document.getElementById('proj-imp').value/100;const placa=document.getElementById('proj-placa').value.trim();if(fat<=0||imp<0||imp>1){alert('Valores inválidos');return;}if(!placa){alert('Placa é obrigatória');return;}p.placa=placa;p.faturamentoBruto=fat;p.impostoPerc=imp;p.custos=[];document.querySelectorAll('#proj-custos > div').forEach((div,i)=>{const n=document.getElementById('proj-c'+i+'-n');const v=document.getElementById('proj-c'+i+'-v');if(n&&v){const nome=n.value;const valStr=v.value.replace(/\D/g,'');const valor=Number(valStr)/100||0;if(nome&&valor>0){p.custos.push({nome:nome,valor:valor});}}});document.getElementById('modal-proj-edit').classList.add('hidden');salvarProjecao();renderProj();}

function salvarProjecao(){localStorage.setItem('flumap_projecao',JSON.stringify(DB.projecao));}

function toggleLance(){mostrarLance=!mostrarLance;renderInv();atualizarGraficoCategorias(filt==='todos'?DB.pagamentos:filt==='empresa'?DB.pagamentos.filter(p=>!p.quem||p.quem==='empresa'):DB.pagamentos.filter(p=>p.quem===filt));}

function atualizarGraficoCategorias(pagamentos){let pagFiltrados=pagamentos;if(!mostrarLance){pagFiltrados=pagamentos.filter(p=>p.cat!=='lance');}const catK=Object.keys(CATS);const catTotals=catK.map(k=>{const items=pagFiltrados.filter(p=>p.cat===k);return{cat:k,nome:CATS[k].nome,cor:CATS[k].cor,total:items.reduce((s,p)=>s+p.valor,0),qtd:items.length}}).filter(c=>c.total>0).sort((a,b)=>b.total-a.total);const labels=catTotals.map(c=>c.nome);const data=catTotals.map(c=>c.total);const colors=catTotals.map(c=>c.cor);ch('ch-cat-pag','bar',labels,[{data:data,backgroundColor:colors,borderColor:colors,borderWidth:1}],{indexAxis:'x',scales:{y:{ticks:{callback:v=>R(v)}}},plugins:{legend:{display:false}}});document.querySelectorAll('[id^="btn-"]').forEach(btn=>btn.classList.remove('btn-p'));document.getElementById('btn-'+filt).classList.add('btn-p');}

function abrirModalEditarInv(id){const inv=DB.investimentos.find(x=>x.id===id);if(!inv)return;document.getElementById('ei-id').value=id;document.getElementById('ei-data').value=inv.data;document.getElementById('ei-desc').value=inv.descricao;document.getElementById('ei-inv').value=inv.investidor;document.getElementById('ei-val').value=R(inv.valor).replace('R$ ','');document.getElementById('ei-dest').value=inv.destinado_para;document.getElementById('ei-cam').value=inv.cam||'';document.getElementById('ei-obs').value=inv.obs||'';document.getElementById('modal-editar-inv').classList.remove('hidden');setTimeout(()=>setCurrencyMask('ei-val'),100);}

function closeModalEditarInv(){document.getElementById('modal-editar-inv').classList.add('hidden');}

function alternarOutrosEdit(){const dest=document.getElementById('ei-dest').value;document.getElementById('ei-dest-outro').style.display=dest==='Outros'?'block':'none';}

function salvarEdicaoInv(){const id=document.getElementById('ei-id').value;const inv=DB.investimentos.find(x=>x.id===id);if(!inv)return;const valStr=document.getElementById('ei-val').value.replace(/\D/g,'');inv.data=document.getElementById('ei-data').value;inv.descricao=document.getElementById('ei-desc').value;inv.investidor=document.getElementById('ei-inv').value;inv.valor=Number(valStr)/100||0;inv.destinado_para=document.getElementById('ei-dest').value;inv.cam=document.getElementById('ei-cam').value||'';inv.obs=document.getElementById('ei-obs').value;atualizarTotaisSocios();save();closeModalEditarInv();renderInvest();atualizarGraficosInvestimento();renderPainel();}

function atualizarTotaisSocios(){SOCIOS.forEach(s=>{const total=DB.investimentos.filter(i=>i.investidor===s.id).reduce((sum,i)=>sum+i.valor,0);const socioInDB=DB.socios.find(x=>x.id===s.id);if(socioInDB)socioInDB.totalPago=total;});}

function atualizarGraficosInvestimento(){atualizarTotaisSocios();const totSocios=DB.socios.reduce((s,x)=>s+x.totalPago,0);const m=totSocios/(DB.socios.length||1);const sokUpdate=DB.socios.map((s,idx)=>{const pct=totSocios>0?s.totalPago/totSocios*100:0;const df=s.totalPago-m;return `<div class="partner-row"><div class="av ${avatarClass(idx)}">${s.iniciais}</div><div style="flex:1"><div style="font-weight:700;font-size:12px">${s.nome}</div><div style="font-size:10px;color:var(--gr5)">Total: ${R(s.totalPago)}</div><div class="prog"><div class="prog-fill ${barClass(idx)}" style="width:${pct}%"></div></div><div style="font-size:10px;margin-top:2px;color:${df>=0?'var(--b6)':'var(--warn)'}>${df>=0?`▲ ${R(df)} acima`:`▼ falta ${R(Math.abs(df))}`}</div></div></div>`}).join('');document.getElementById('inv-s').innerHTML=sokUpdate;const socioColors=['#1565C0','#43A047','#D97706','#DC2626'];ch('ch3-inv','doughnut',DB.socios.map(s=>s.nome),[{data:DB.socios.map(s=>s.totalPago),backgroundColor:DB.socios.map((_,i)=>socioColors[i]||'#BDBDBD'),borderWidth:3,borderColor:'#fff'}],{plugins:{legend:{position:'bottom'},tooltip:{callbacks:{label:ctx=>`${ctx.label}: ${Math.round((ctx.parsed/totSocios)*100)}%`}}},cutout:'50%'});}

function deletarInvestimento(id){if(confirm('Tem certeza que deseja deletar este investimento? Esta ação não pode ser desfeita.')){DB.investimentos=DB.investimentos.filter(i=>i.id!==id);atualizarTotaisSocios();save();renderInvest();atualizarGraficosInvestimento();renderPainel();}}

function save(){localStorage.setItem('flumap_v2',JSON.stringify(DB));}

if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}
